    'ancient_map_jiuyu_title' => 'Cửu Vực Thu Lệnh Đồ (1121)',
    'ancient_map_jiuyu_year' => '1121',
    'ancient_map_jiuyu_body' => '<p>சீனாவின் சாங் வம்சத்தின் முழுமையான தேசிய எல்லைகளை காட்டும் மிக ஆரம்ப வரைபடம்; இது <strong>1121</strong> ஆம் ஆண்டு (Xuanhe 3ஆம் ஆண்டு) தோன்றியது. கல்லில் செதுக்கப்பட்டது; 1960 இல் சிச்சுவான் மாகாணம், வோங் மாவட்டத்தில் கண்டுபிடிக்கப்பட்டது.</p><p>இந்த வரைபடத்தில் சாங் வம்சத்தின் தெற்கு எல்லை <strong>கியோங்சோ (ஹைனான்)</strong> வரை மட்டுமே செல்கிறது. ஹைனான் தீவின் வடிவம் நவீன வரைபடத்திற்கும் நெருக்கமாக துல்லியமாக வரையப்பட்டுள்ளது.</p>',
    'ancient_map_kangxi_guangdong_title' => 'காங்சி காலக் குவாங்டோங் — மிகத் தெற்கு ஹைனானில்',
    'ancient_map_kangxi_guangdong_year' => '1685–1701',
    'ancient_map_kangxi_guangdong_body' => '<p>17ஆம் நூற்றாண்டின் இறுதி–18ஆம் நூற்றாண்டின் தொடக்கம்: காங்சி ஆட்சிக் காலத்தில், பட்டு மீது வரையப்பட்டதும் மாகாண வரலாற்றுக் குறிப்புகளில் இடம்பெற்றதும் ஆகிய குவாங்டோங் மாகாண நிர்வாக வரைபடங்களின் தொடர்ச்சி.</p><p><strong>குவாங்டோங் முழு வரைபடம்</strong> (சுமார் 1685): <strong>295×196 செ.மீ.</strong> அளவில், பட்டு மீது வண்ணமிட்டு வரையப்பட்டது; மாகாண எல்லை <strong>கியோங்சோ府 (ஹைனான்)</strong> வரை மட்டுமே நீள்கிறது.</p><p><strong>குவாங்டோங் முழு வரைபடம்</strong> மற்றும் ஹைனான் தீவின் விரிவான பகுதி (சுமார் 1700–1701): தெற்கு எல்லை ஹைனான் தீவு பகுதியில் நிற்கிறது — பராசல் தீவுகள், ஸ்ப்ராட்லி தீவுகள் எதுவும் இல்லை.</p>',
