    'ancient_map_qianlong_gazetteer_title' => 'ஹுவாங்சோங் யூடி & குவாங்டோங் டொங்ழி',
    'ancient_map_qianlong_gazetteer_year' => '1728–1751',
    'ancient_map_qianlong_gazetteer_body' => '<p><strong>யோங்ழெங்–சியென்புலோங்</strong> காலத்தில்: தேசிய வரைபடங்களும் <em>குவாங்டோங் டொங்ழி</em>யும் நிர்வாக தெற்கு எல்லை <strong>ஹைனான் தீவில் உள்ள கியோங்சோ府</strong> என்பதைக் கணிக்கின்றன.</p><p><strong>ஹுவாங்சோங் யூடி முழு வரைபடம்</strong> (1728–1729): <strong>57×57.3 செ.மீ.</strong>, தெற்கு எல்லை கியோங்சோ வரை மட்டுமே.</p><p>மாகாண வரலாற்று குறிப்புகளில்: <em>குவாங்டோங் மாகாணத்தின் முழு வரைபடம்</em> (ஹே யூலின்) மற்றும் <em>கியோங்சோ府 முழு வரைபடம்</em> (யுவான் யுவான்) — நிர்வாக வரம்பு ஹைனானைத் தாண்டவில்லை.</p>',
    'ancient_map_qianlong_gazetteer_img1_caption' => 'ஹுவாங்சோங் யூடி முழு வரைபடம் (1728–1729)',
    'ancient_map_qianlong_gazetteer_img2_caption' => 'குவாங்டோங் மாகாணத்தின் முழு வரைபடம்',
    'ancient_map_qianlong_gazetteer_img3_caption' => 'கியோங்சோ府 முழு வரைபடம்',
    'ancient_map_jiaqing_atlas_1850_title' => 'சிங் இருநகரம் பதினெட்டு மாகாண எல்லை முழு வரைபடம் (1850)',
    'ancient_map_jiaqing_atlas_1850_year' => '1850',
    'ancient_map_jiaqing_atlas_1850_body' => '<p><em>சிங் இருநகரம் பதினெட்டு மாகாண எல்லை முழு வரைபடம்</em> என்ற நூலில், ஆசிரியர் டோங் தியாவோ வென் சாவோவெய்மோன் — ஜப்பானிய ஜியாக்கிங் 3ஆம் ஆண்டு பதிப்பு (<strong>1850</strong>).</p><p>இதே நூலில் உள்ள <em>இரு நகரம் பதினெட்டு மாகாணங்களின் முழு வரைபடம்</em> மற்றும் <em>குவாங்டோங் முழு வரைபடம்</em> இரண்டும் சீனாவின் தெற்குக் கோடையாக ஹைனான் தீவை மட்டும் காட்டுகின்றன. தரவு Chữ Đình Phúc / VietNamNet-இன் சீன மின்னணு நூலகத் தொகுப்பிலிருந்து.</p>',
    'ancient_map_jiaqing_atlas_1850_img1_caption' => 'இரு நகரம் பதினெட்டு மாகாணங்களின் முழு வரைபடம்',
    'ancient_map_jiaqing_atlas_1850_img2_caption' => 'குவாங்டோங் முழு வரைபடம்',
    'ancient_map_guangxu_coastal_title' => 'குவாங்டோங் கரையோர கடல் & இராணுவ வரைபடம்',
    'ancient_map_guangxu_coastal_year' => '1862–1866',
    'ancient_map_guangxu_coastal_body' => '<p><strong>குவாங்சு</strong> காலம் — ஒரே புவியியல் உண்மையை உறுதிப்படுத்தும் இரண்டு வகை ஆதாரங்கள்:</p><p><strong>ஏழு மாகாண கரையோர முழு கடல் வரைபடம்</strong> (சுமார் 1862–1908): ஏழு கரையோர மாகாணங்களின் கடற்பரப்பு, <strong>28×914.2 செ.மீ.</strong>; தென் சீனக் கடல் <strong>18° வட அகலம்</strong> ஐத் தாண்டவில்லை.</p><p><strong>குவாங்டோங் நீர்ப்படை முகாம் படைத்துறை தங்குமிடம் வரைபடம்</strong> (1866க்கு பின்): <strong>32×560 செ.மீ.</strong> அளவிலான இராணுவ வரைபடம்; சீனா அழைக்கும் மேற்குத் தீவுகள், தெற்குத் தீவுகள் (வியட்நாமின் பராசல் தீவுகள் மற்றும் ஸ்ப்ராட்லி தீவுகளுக்கான பெயர்கள்) தொடர்பான எந்தத் தீவுக்குழுவும் இல்லை.</p>',
    'ancient_map_guangxu_coastal_img1_caption' => 'ஏழு மாகாண கரையோர முழு கடல் வரைபடம்',
    'ancient_map_guangxu_coastal_img2_caption' => 'குவாங்டோங் நீர்ப்படை முகாம் படைத்துறை தங்குமிடம் வரைபடம்',
    'ancient_map_daqing_yitong_title' => 'டா சிங் முழு ஒன்றிணைந்த வரைபடம்',
    'ancient_map_daqing_yitong_year' => '19ஆம் நூற்றாண்டின் இறுதி',
    'ancient_map_daqing_yitong_body' => '<p>டா சிங் பேரரசின் முழு வரைபடம். கடல்பரப்பில் ஃபெங்மா (கொரியாவின் தெற்கில்), லியூக்யூ (ஜெஜியாஙின் கிழக்கில்), தைவான் (புஜியானின் கிழக்கில்), மேலும் <strong>கியோங்சோ, யா்சோ</strong> ஹைனான் தீவிற்குள் — குவாங்டோங் நிலப்பகுதியின் தெற்கில் — மட்டுமே குறிக்கப்பட்டுள்ளன.</p>',
    'ancient_map_late_qing_prints_title' => 'காலத்தாழ்ந்த சிங் அச்சு அட்லஸ் — 1904–1908',
    'ancient_map_late_qing_prints_year' => '1904–1908',
    'ancient_map_late_qing_prints_body' => '<p><strong>1904</strong> முதல் <strong>1908</strong> வரை சீனாவும் வெளிநாட்டு அச்சகங்களும் வெளியிட்ட அட்லஸ்களின் தொடர் — ஒரே புவியியல் முடிவு: சீனாவின் தெற்கே ஹைனான் தீவு, <strong>பராசல் தீவுகள், ஸ்ப்ராட்லி தீவுகள் சேர்க்கப்படவில்லை</strong>.</p><p>குறிப்பிடத்தக்கவை: <em>ஹுவாங்சோங் நேரடி மாகாணப் புவியியல் முழு வரைபடம்</em> (1904, வியட்நாம் வரலாற்று அருங்காட்சியகத்திற்கு பரிசளிக்கப்பட்டது); <em>சிங் வம்சப் புவியியல் வரைபடத் தொகுப்பு</em> (1905); <em>டா சிங் பேரரசின் மாகாணத் துல்லிய வரைபடம்</em> (1907, டோக்கியோ); <em>டா சிங் பேரரசின் முழு வரைபடம்</em> (1908, ஷாங்காய் கமர்ஷியல் பிரஸ்).</p>',
    'ancient_map_late_qing_prints_img1_caption' => 'ஹுவாங்சோங் நேரடி மாகாணப் புவியியல் முழு வரைபடம் (1904)',
    'ancient_map_late_qing_prints_img2_caption' => 'டா சிங் பேரரசு — சிங் வம்சப் புவியியல் வரைபடத் தொகுப்பு (1905)',
    'ancient_map_late_qing_prints_img3_caption' => 'டா சிங் பேரரசின் முழு வரைபடம் — மாகாணத் துல்லிய வரைபடம் (1907)',
    'ancient_map_late_qing_prints_img4_caption' => 'குவாங்டோங் — மாகாணத் துல்லிய வரைபடம் (1907)',
    'ancient_map_late_qing_prints_img5_caption' => 'டா சிங் பேரரசின் முழு வரைபடம் (1908)',
    'ancient_map_late_qing_prints_img6_caption' => 'குவாங்டோங் — முழு வரைபடம் (1908)',
    'ancient_map_xinhai_1912_title' => 'சிங் நாடு பெரும் வரைபடம் — சின்ஹைப் புரட்சி (1912)',
    'ancient_map_xinhai_1912_year' => '1912',
    'ancient_map_xinhai_1912_body' => '<p><em>சிங் நாடு பெரும் வரைபடம் சின்ஹை புரட்சியின் குழப்ப இடக் குறிப்புகள்</em> — <strong>1912</strong> ஆம் ஆண்டு (மெய்ஜி 44ஆம் ஆண்டு) ஒசாகாவில் உள்ள ஸெய்ஹொன் அச்சு கூட்டுறவு நிறுவனம் (ஜப்பான்) மூலம் வெளியிடப்பட்டது. தற்போது கலிபோர்னியா பல்கலைக்கழகம், பெர்க்லி (அமெரிக்கா) நூலகத்தில் பாதுகாக்கப்பட்டுள்ளது.</p>',
    'ancient_map_roc_atlas_title' => 'சீனக் குடியரசு — 1933–1939 புவியியல் அட்லஸ்',
    'ancient_map_roc_atlas_year' => '1933–1939',
    'ancient_map_roc_atlas_body' => '<p>சீனக் குடியரசு காலத்தில், சீனாவிலும் டோக்கியோவிலும் அச்சிடப்பட்ட அட்லஸ்கள் ஹைனான் தீவு வரைதான் மிகத் தெற்கு எல்லை என்பதைத் தொடர்ந்து உறுதிப்படுத்தின:</p><p><em>சீனக் குடியரசின் மாகாண வரைபட நூல்</em> (<strong>1933</strong>); <em>சீனக் குடியரசின் 24ஆம் ஆண்டு தேசிய மாகாணப் பிரதேசம்</em> (<strong>1935</strong>); <em>சீனா வரைபட நூல்</em> — மட்சுடா தோமோனின், டோக்கியோ ஷிகைகேஷோ (<strong>1939</strong>) — இதில் நிலப்பரப்பு வரைபடும் குவாங்டோங் மாகாண வரைபடும் அடங்கும்.</p>',
    'ancient_map_roc_atlas_img1_caption' => 'சீனக் குடியரசு முழு வரைபடம் (1933)',
    'ancient_map_roc_atlas_img2_caption' => 'சீனக் குடியரசு முழு வரைபடம் (1935)',
    'ancient_map_roc_atlas_img3_caption' => 'மூலநிலத்தின் வடிவமைப்பு வரைபடம் (1939)',
    'ancient_map_roc_atlas_img4_caption' => 'குவாங்டோங் — சீனா வரைபட நூல் (1939)',
